for (const item of items) {
  let message = item.json.message;

  message = (message || "").trim() || "Unknown";

  item.json.message =
    message.charAt(0).toUpperCase() + message.slice(1);
}

return items;

for (const item of items) {
  try {
    const text = item.json.content?.parts?.[0]?.text || "";

    const clean = text
      .replace(/```json/g, "")
      .replace(/```/g, "")
      .trim();

    const result = JSON.parse(clean);

    const errors = [];

    if (result.missing_required_fields?.length) {
      errors.push(
        `${result.missing_required_fields.join(', ')} ${
          result.missing_required_fields.length === 1 ? 'is' : 'are'
        } missing`
      );
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (
      result.email !== null &&
      !emailRegex.test(result.email)
    ) {
      errors.push(`Invalid email format: ${result.email}`);
    }

    if (errors.length) {
      throw new Error(errors.join(' | '));
    }

    const output = {
      success: true,
      data: result
    };

    if (!result.missing_required_fields?.length) {
      delete output.data.missing_required_fields;
    }

    item.json = output;

  } catch (e) {
    item.json = {
      success: false,
      error: e.message
    };
  }
}
return items;
